#' Estimate the parameters of the regional distribution
#'
#' @param best_model
#' A 6-column \code{data.frame} as generated by \code{Best_model()}.
#' \itemize{
#'   \item Columns 1--5: \code{mu0}, \code{mu1}, \code{sigma0},
#'         \code{sigma1}, \code{shape}.
#'   \item Column 6: \code{size} (sample size per site, used as weight).
#' }
#'
#' @returns
#' A one-row \code{data.frame} with the size-weighted regional parameters of a
#' time-varying generalised extreme value distribution.
#'
#' @export
#' @importFrom stats weighted.mean
#' 
#' @examples
#' add.data   <- Dataset_add(TmaxCPC_SP)
#' best.parms <- Best_model(add.data = add.data$add_data)
#' Reg_par(best_model = best.parms$atsite.models)

Reg_par <- function(best_model) {
  check_best_model_df(best_model) # defined in input_checks.R

  w <- best_model$size
  par_cols <- c("mu0", "mu1", "sigma0", "sigma1", "shape")

  # Compute all five weighted means in one vectorised call,
  # then name the results — no dplyr needed.
  wm <- vapply(
    best_model[par_cols],
    weighted.mean,
    w = w,
    na.rm = TRUE,
    FUN.VALUE = numeric(1)
  )

  names(wm) <- paste0("weighted_", par_cols)

  as.data.frame(as.list(wm))
}
